worked_example.final_code:
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
import java.io.*;
import java.nio.file.*;
import java.util.*;

record Holding(String symbol, int shares, double buyPrice, double curPrice, String notes) {}

public class PortfolioProcessor {
    static List<String> parseCSVLine(String line) {
        List<String> fields = new ArrayList<>();
        StringBuilder cur = new StringBuilder();
        boolean inQ = false;
        for (int i = 0; i < line.length(); i++) {
            char c = line.charAt(i);
            if (c == '"') {
                if (inQ && i+1 < line.length() && line.charAt(i+1) == '"') { cur.append('"'); i++; }
                else inQ = !inQ;
            } else if (c == ',' && !inQ) { fields.add(cur.toString()); cur.setLength(0); }
            else cur.append(c);
        }
        fields.add(cur.toString());
        return fields;
    }

    static String q(String v) {
        if (v == null) return "";
        if (!v.contains(",") && !v.contains("\"")) return v;
        return "\"" + v.replace("\"", "\"\"") + "\"";
    }

    public static void main(String[] args) throws Exception {
        Path csv = Path.of("portfolio.csv");
        Files.writeString(csv,
            "symbol,shares,buyPrice,currentPrice,notes\n" +
            "TCS,10,2760,3890,\"Long term, quality stock\"\n" +
            "RELIANCE,20,2197,2450,Diversified\n" +
            "WIPRO,50,450,412,\"Watching, volatile\"");

        List<Holding> holdings = new ArrayList<>();
        try (BufferedReader br = Files.newBufferedReader(csv)) {
            br.readLine();
            String line;
            while ((line = br.readLine()) != null) {
                var c = parseCSVLine(line);
                holdings.add(new Holding(c.get(0), Integer.parseInt(c.get(1)),
                    Double.parseDouble(c.get(2)), Double.parseDouble(c.get(3)),
                    c.size() > 4 ? c.get(4) : ""));
            }
        }

        ObjectMapper mapper = new ObjectMapper();
        ArrayNode report = mapper.createArrayNode();
        double total = 0;
        for (Holding h : holdings) {
            double val = h.shares() * h.curPrice(); total += val;
            double pnl = (h.curPrice() / h.buyPrice() - 1) * 100;
            ObjectNode n = mapper.createObjectNode();
            n.put("symbol", h.symbol()).put("shares", h.shares())
             .put("value", (long)val)
             .put("pnlPct", Math.round(pnl*10)/10.0);
            report.add(n);
        }
        Files.writeString(Path.of("portfolio.json"),
            mapper.writerWithDefaultPrettyPrinter().writeValueAsString(report));
        System.out.println("Parsed: " + holdings.size() + " holdings");
        System.out.println("Total value: ₹" + (long)total);
        System.out.println("TCS notes: " + holdings.get(0).notes());
    }
}

